document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".moto-card").forEach(e=>{const t=e.querySelector(".moto-card-img"),o=e.querySelectorAll(".moto-color-dot");o.forEach(e=>{e.addEventListener("mouseenter",function(){const e=this.getAttribute("data-image");e&&t&&(t.src=e,o.forEach(e=>e.classList.remove("active")),this.classList.add("active"))})});const c=e.querySelector(".moto-colors-dots");c&&c.addEventListener("mouseleave",function(){})})});